#!/bin/sh
# SPDX-License-Identifier: PMPL-1.0-or-later
# SPDX-FileCopyrightText: 2026 Jonathan D.A. Jewell <j.d.a.jewell@open.ac.uk>
#
# gen-repos-manifest.sh — regenerate reposystem/repos.toml from the estate
# superproject's .gitmodules.
#
# repos.toml is the aggregator's coordination index. It is GENERATED, never
# hand-edited (per 0-AI-MANIFEST.a2ml: keep generated files regenerable from a
# documented command). The single source of truth for code remains the flat
# clones in $REPOS_DIR; this file only records which repos exist and how to
# group them into cross-repo "threads".
#
# Hand-maintained grouping lives in repos.groups.toml (NOT generated); this
# script preserves it verbatim by appending an include hint, so regeneration
# never destroys epic/group assignments.
#
# Usage: scripts/gen-repos-manifest.sh [GITMODULES] [OUT]
#   GITMODULES defaults to ../repos-monorepo/.gitmodules (relative to repo root)
#   OUT        defaults to ./repos.toml
set -eu

ROOT=$(CDPATH= cd -- "$(dirname -- "$0")/.." && pwd)
GITMODULES=${1:-"$ROOT/../repos-monorepo/.gitmodules"}
OUT=${2:-"$ROOT/repos.toml"}

[ -f "$GITMODULES" ] || { echo "error: .gitmodules not found: $GITMODULES" >&2; exit 1; }

today=$(date -I)
count=$(grep -c '^\[submodule ' "$GITMODULES" || true)

tmp=$(mktemp)
trap 'rm -f "$tmp"' EXIT

{
  echo "# GENERATED by scripts/gen-repos-manifest.sh — DO NOT EDIT BY HAND."
  echo "# Regenerate: just repos-manifest"
  echo "# Source of truth for code = flat clones in \$REPOS_DIR (~/dev/repos)."
  echo "# This file is only the aggregator's coordination index."
  echo "# Hand-maintained epic/group assignments live in repos.groups.toml."
  echo
  echo "[meta]"
  echo "generated = \"$today\""
  echo "source = \"$(basename "$(dirname "$GITMODULES")")/.gitmodules\""
  echo "count = $count"
  echo

  # Walk .gitmodules directly (do not trust `git submodule status`: it aborts
  # on the first URL-less entry — see scripts/gitlink-drift.jl header).
  name= ; path= ; url=
  emit() {
    [ -n "$name" ] || return 0
    # kind heuristic: gives ready-made coarse buckets; refine in groups file.
    case "$name" in
      *.jl)          kind=julia ;;
      *-ecosystem)   kind=ecosystem ;;
      *.github.io)   kind=site ;;
      *)             kind=repo ;;
    esac
    {
      echo "[[repo]]"
      echo "name = \"$name\""
      echo "path = \"$path\""
      echo "url  = \"$url\""
      echo "kind = \"$kind\""
      echo
    } >> "$tmp.repos"
  }
  : > "$tmp.repos"
  while IFS= read -r line; do
    case "$line" in
      '[submodule '*) emit; name=$(echo "$line" | sed -e 's/^\[submodule "//' -e 's/"\]$//'); path= ; url= ;;
      *path\ =*)      path=$(echo "$line" | sed -e 's/^[[:space:]]*path[[:space:]]*=[[:space:]]*//') ;;
      *url\ =*)       url=$(echo  "$line" | sed -e 's/^[[:space:]]*url[[:space:]]*=[[:space:]]*//') ;;
    esac
  done < "$GITMODULES"
  emit
  cat "$tmp.repos"
  rm -f "$tmp.repos"
} > "$tmp"

mv "$tmp" "$OUT"
trap - EXIT
echo "wrote $OUT ($count repos)"
